function transliterate(word, targetLang, translation) {
    if (['en', 'es', 'fr'].includes(targetLang)) {
        let res = word.toLowerCase().replace(/[^a-z]/g, '');
        if (res === translation.toLowerCase()) {
            if (targetLang === 'en') res += "z";
            if (targetLang === 'es') res += "o";
            if (targetLang === 'fr') res += "e";
        }
        return res || id + "x";
    }
    const clean = word.toLowerCase().replace(/[^a-z]/g, '');
    const map = PHONETIC_MAPS[targetLang];
    let res = "";
    let i = 0;
    while (i < (clean.length || 1)) {
        if (!clean[i]) break;
        if (i+1 < clean.length && map[clean.substring(i, i+2)]) { res += map[clean.substring(i, i+2)]; i+=2; }
        else if (map[clean[i]]) { res += map[clean[i]]; i++; }
        else { i++; }
    }
    let final = res || (targetLang === 'hi' ? 'शब्द' : (targetLang === 'zh' ? '词' : 'لفظ'));
    if (final === translation) {
        if (targetLang === 'ur' || targetLang === 'ar') final += "ہ";
        if (targetLang === 'hi') final += "्";
    }
    return final;
}

function getTranslation(id, lang) {
    const core = {
        "i": { en: "I", es: "Yo", ur: "میں", ar: "أنا", hi: "मैं", zh: "我", fr: "Je" },
        "you": { en: "You", es: "Tú", ur: "آپ", ar: "أنت", hi: "आप", zh: "你", fr: "Tu" },
        "want": { en: "Want", es: "Querer", ur: "چاہنا", ar: "أريد", hi: "चाहना", zh: "想要", fr: "Vouloir" }
    };
    if (core[id] && core[id][lang]) return core[id][lang];
    if (lang === 'en') return id.charAt(0).toUpperCase() + id.slice(1);
    if (['en', 'es', 'fr'].includes(lang)) return id.toLowerCase() + (lang === 'es' ? "es" : "fr");
    return transliterate(id, lang, "");
}

function generateDoodleShapes(id) {
    const shapes = new Set(["stroke", "outline", "compact"]);
    const lid = id.toLowerCase();
    if (/(round|circle|apple|ball|potato|onion|face|eye|moon|head|ear|mouth|pill|plate|bowl|cup|orange|grape|berry|lemon|lime|seed|sun|star|button|bulb|coin|egg)/.test(lid)) { shapes.add("circle"); shapes.add("round"); shapes.add("curved"); }
    else if (/(box|square|table|book|room|window|bed|fridge|screen|wall|floor|desk|sofa|shelf|rug|sheet|map|card|flag|door)/.test(lid)) { shapes.add("rectangle"); shapes.add("flat"); shapes.add("outline"); }
    else if (/(pointy|triangle|mountain|carrot|okra|knife|saw|pen|pencil|needle|fork|tooth|nose|spine|hill|pyramid)/.test(lid)) { shapes.add("triangle"); shapes.add("elongated"); }
    else { shapes.add("blob"); shapes.add("irregular"); }
    if (/(water|milk|juice|tea|coffee|soup|oil|honey|wave|sea|river|lake|rain|tear|blood|sweat|breath|wind|storm|fog|mist|sauce|syrup)/.test(lid)) { shapes.add("wave"); shapes.add("smooth"); shapes.add("arc"); }
    if (/(pain|hurt|fire|lightning|zigzag|urgent|fever|cough|sneeze|itch|ache|cramp|spasm|faint|emergency|crisis|danger|fear|angry|shocked)/.test(lid)) { shapes.add("zigzag"); shapes.add("scribble"); }
    const final = Array.from(shapes);
    while (final.length < 5) final.push("simple");
    return final.slice(0, 10);
}

